//! Output formatting for CLI responses.
//! Generated by hr-graph. DO NOT EDIT.

use clap::ValueEnum;
use serde_json::Value;

#[derive(Debug, Clone, Copy, ValueEnum)]
pub enum OutputFormat {
    /// Human-readable table format
    Table,
    /// Raw JSON
    Json,
    /// Pretty-printed JSON
    JsonPretty,
}

impl OutputFormat {
    pub fn print(&self, value: &Value) -> anyhow::Result<()> {
        match self {
            OutputFormat::Json => {
                println!("{}", serde_json::to_string(value)?);
            }
            OutputFormat::JsonPretty => {
                println!("{}", serde_json::to_string_pretty(value)?);
            }
            OutputFormat::Table => {
                print_table(value);
            }
        }
        Ok(())
    }
}

fn print_table(value: &Value) {
    match value {
        Value::Array(items) => {
            if items.is_empty() {
                println!("No results.");
                return;
            }
            // Collect column headers from first object
            let headers: Vec<String> = if let Some(Value::Object(first)) = items.first() {
                first.keys().cloned().collect()
            } else {
                println!("{}", serde_json::to_string_pretty(&value).unwrap_or_default());
                return;
            };

            // Compute column widths
            let mut widths: Vec<usize> = headers.iter().map(|h| h.len()).collect();
            let rows: Vec<Vec<String>> = items
                .iter()
                .map(|item| {
                    headers
                        .iter()
                        .enumerate()
                        .map(|(i, h)| {
                            let cell = format_cell(item.get(h));
                            if cell.len() > widths[i] {
                                widths[i] = cell.len();
                            }
                            cell
                        })
                        .collect()
                })
                .collect();

            // Cap column widths for readability
            for w in &mut widths {
                if *w > 40 {
                    *w = 40;
                }
            }

            // Print header
            let header_line: Vec<String> = headers
                .iter()
                .enumerate()
                .map(|(i, h)| format!("{:<width$}", h, width = widths[i]))
                .collect();
            println!("{}", header_line.join("  "));
            let sep: Vec<String> = widths.iter().map(|w| "-".repeat(*w)).collect();
            println!("{}", sep.join("  "));

            // Print rows
            for row in &rows {
                let cells: Vec<String> = row
                    .iter()
                    .enumerate()
                    .map(|(i, cell)| {
                        let truncated = if cell.len() > widths[i] {
                            format!("{}...", &cell[..widths[i].saturating_sub(3)])
                        } else {
                            cell.clone()
                        };
                        format!("{:<width$}", truncated, width = widths[i])
                    })
                    .collect();
                println!("{}", cells.join("  "));
            }
            println!("\n{} row(s)", rows.len());
        }
        Value::Object(obj) => {
            // Single object: print as key-value pairs
            let max_key_len = obj.keys().map(|k| k.len()).max().unwrap_or(0);
            for (key, val) in obj {
                println!(
                    "{:<width$}  {}",
                    key,
                    format_cell(Some(val)),
                    width = max_key_len
                );
            }
        }
        other => {
            println!("{}", serde_json::to_string_pretty(other).unwrap_or_default());
        }
    }
}

fn format_cell(value: Option<&Value>) -> String {
    match value {
        None | Some(Value::Null) => "-".to_string(),
        Some(Value::String(s)) => s.clone(),
        Some(Value::Number(n)) => n.to_string(),
        Some(Value::Bool(b)) => b.to_string(),
        Some(Value::Array(a)) => format!("[{} items]", a.len()),
        Some(Value::Object(_)) => "{...}".to_string(),
    }
}
